arguments.argument:
if global.gamePaused=false
{
  switchTime+=1
  if switchTime>=switchDelay
  {
    if bCanDealDamage=0
    {
      sprite_index=sTimedSpikeOut
      bCanDealDamage=1
    }
    else
    {
      sprite_index=sTimedSpikeIn
      bCanDealDamage=0
    }
    switchTime=0
  }
}
